    public static final class PaymentProcessor {

        public static PaymentResponse process(PaymentRequest req) {
            String txId = "TX-" + UUID.randomUUID();
            if (req.amount.compareTo(new BigDecimal("10000.00")) > 0) {
                return new PaymentResponse(req.requestId, txId, "DECLINED", null, "Amount exceeds limit");
            }
            if (req.method == PaymentMethod.CARD) {
                if (!luhn(req.cardNumber)) {
                    return new PaymentResponse(req.requestId, txId, "DECLINED", null, "Invalid card number");
                }
            }
            String auth = "AUTH" + (100000 + (int) (Math.random() * 900000));
            return new PaymentResponse(req.requestId, txId, "APPROVED", auth, "Approved");
        }

        private static boolean luhn(String pan) {
            if (pan == null) return false;
            String s = pan.replaceAll("\\s+", "");
            if (!s.matches("\\d{12,19}")) return false;
            int sum = 0;
            boolean alt = false;
            for (int i = s.length() - 1; i >= 0; i--) {
                int n = s.charAt(i) - '0';
                if (alt) {
                    n *= 2;
                    if (n > 9) n -= 9;
                }
                sum += n;
                alt = !alt;
            }
            return sum % 10 == 0;
        }
    }

