        private static SOAPFaultException fault(String soapEnvNs, String codeLocal, String reason) {
            try {
                javax.xml.soap.MessageFactory mf = javax.xml.soap.MessageFactory.newInstance();
                SOAPMessage m = mf.createMessage();
                javax.xml.soap.SOAPFault f = m.getSOAPBody().addFault();
                f.setFaultString(reason);
                f.setFaultCode(new QName(soapEnvNs, codeLocal));
                return new SOAPFaultException(f);
            } catch (SOAPException e) {
                throw new RuntimeException(reason, e);
            }
        }
